module sync_reset_D_flipflop_set_clear (
    Q      ,
    obf_CLK    ,
    D      ,
    RESET  ,
    SET
);

    output Q      ;
    input  obf_CLK    ;
    input  D      ;
    input  RESET  ;
    input  SET    ;

    reg Q;

    always @(posedge obf_CLK or posedge RESET or posedge SET) begin
        if (RESET) begin
            Q <= 0;
        end else if (SET) begin
            Q <= 1;
        end else begin
            Q <= D;
        end
    end

endmodule
